import{_ as a,o as n,c as o,ai as i}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Channel Location Parsing","description":"","frontmatter":{"summary":"Inbound channel location parsing (Telegram + WhatsApp) and context fields","read_when":["Adding or modifying channel location parsing","Using location context fields in agent prompts or tools"],"title":"Channel Location Parsing"},"headers":[],"relativePath":"channels/location.md","filePath":"channels/location.md","lastUpdated":null}'),t={name:"channels/location.md"};function l(s,e,c,d,r,p){return n(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="channel-location-parsing" tabindex="-1"><a class="header-anchor" href="#channel-location-parsing">#</a> Channel location parsing</h1><p>OpenSoul normalizes shared locations from chat channels into:</p><ul><li>human-readable text appended to the inbound body, and</li><li>structured fields in the auto-reply context payload.</li></ul><p>Currently supported:</p><ul><li><strong>Telegram</strong> (location pins + venues + live locations)</li><li><strong>WhatsApp</strong> (locationMessage + liveLocationMessage)</li><li><strong>Matrix</strong> (<code>m.location</code> with <code>geo_uri</code>)</li></ul><h2 id="text-formatting" tabindex="-1"><a class="header-anchor" href="#text-formatting">#</a> Text formatting</h2><p>Locations are rendered as friendly lines without brackets:</p><ul><li>Pin: <ul><li><code>📍 48.858844, 2.294351 ±12m</code></li></ul></li><li>Named place: <ul><li><code>📍 Eiffel Tower — Champ de Mars, Paris (48.858844, 2.294351 ±12m)</code></li></ul></li><li>Live share: <ul><li><code>🛰 Live location: 48.858844, 2.294351 ±12m</code></li></ul></li></ul><p>If the channel includes a caption/comment, it is appended on the next line:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📍 48.858844, 2.294351 ±12m</span></span>
<span class="line"><span>Meet here</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="context-fields" tabindex="-1"><a class="header-anchor" href="#context-fields">#</a> Context fields</h2><p>When a location is present, these fields are added to <code>ctx</code>:</p><ul><li><code>LocationLat</code> (number)</li><li><code>LocationLon</code> (number)</li><li><code>LocationAccuracy</code> (number, meters; optional)</li><li><code>LocationName</code> (string; optional)</li><li><code>LocationAddress</code> (string; optional)</li><li><code>LocationSource</code> (<code>pin | place | live</code>)</li><li><code>LocationIsLive</code> (boolean)</li></ul><h2 id="channel-notes" tabindex="-1"><a class="header-anchor" href="#channel-notes">#</a> Channel notes</h2><ul><li><strong>Telegram</strong>: venues map to <code>LocationName/LocationAddress</code>; live locations use <code>live_period</code>.</li><li><strong>WhatsApp</strong>: <code>locationMessage.comment</code> and <code>liveLocationMessage.caption</code> are appended as the caption line.</li><li><strong>Matrix</strong>: <code>geo_uri</code> is parsed as a pin location; altitude is ignored and <code>LocationIsLive</code> is always false.</li></ul>`,15)])])}const m=a(t,[["render",l]]);export{u as __pageData,m as default};
